import{_ as i,o as n,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"10A. Gender Based Discrimination","description":"","frontmatter":{"title":"10A. Gender Based Discrimination","eba":"Nurses and Midwives 2024-2028","topics":["preliminary","discrimination"]},"headers":[],"relativePath":"ebas/nurses-midwives/preliminary/10A-gender-based-discrimination.md","filePath":"ebas/nurses-midwives/preliminary/10A-gender-based-discrimination.md"}'),s={name:"ebas/nurses-midwives/preliminary/10A-gender-based-discrimination.md"};function a(o,e,d,p,m,g){return n(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_10a-gender-based-discrimination" tabindex="-1">10A. Gender Based Discrimination <a class="header-anchor" href="#_10a-gender-based-discrimination" aria-label="Permalink to &quot;10A. Gender Based Discrimination&quot;">​</a></h1><p><strong>10A.1</strong> The parties at clause 10A.4 agree, in conjunction with the DOH, to establish a Gender- Based Standing Committee (GBSC) within three months of the commencement of this Agreement.</p><p><strong>10A.2</strong> The purpose of the GBSC will be to:</p><p><strong>(a)</strong> review audit results;</p><p>Part A - Preliminary</p><p><strong>(d)</strong> promote gender equity initiatives;</p><p><strong>(e)</strong> identify and address any gender pay gaps in the public sector organisation; and</p><p><strong>(f)</strong> promote job security.</p><p><strong>10A.3</strong> The GBSC will schedule a minimum of four meetings per year.</p><p><strong>10A.4</strong> The GBSC will be comprised of:</p><p><strong>(a)</strong> representative Employers through their CEOs or their nominees;</p><p><strong>(g)</strong> the Unions; and</p><p><strong>(h)</strong> the VHIA.</p><p>The GBSC may, by unanimous agreement of its sitting members, also include other health sector unions who are not covered by this Agreement to meet the objectives at clause 10A.2.</p><p><strong>10A.5</strong> The Employer’s gender equity activities, including Audit and Action Plan will be a standing agenda item at WIC meetings.</p><p>Plain language terms: gender discrimination, sex discrimination, pay equity.</p>',16)])])}const h=i(s,[["render",a]]);export{l as __pageData,h as default};
